201: pub fn zeroed(bytes: []const u8) bool {
202:     // This implementation already gets vectorized
203:     // https://godbolt.org/z/46cMsPKPc
204:     var byte_bits: u8 = 0;
205:     for (bytes) |byte| {
206:         byte_bits |= byte;
207:     }
