354: /// An alternative to the default logFn from `std.log`, which prepends a UTC timestamp.
355: pub fn log_with_timestamp(
356:     comptime message_level: std.log.Level,
357:     comptime scope: @Type(.enum_literal),
358:     comptime format: []const u8,
359:     args: anytype,
360: ) void {
361:     const level_text = comptime message_level.asText();
362:     const scope_prefix = if (scope == .default) ": " else "(" ++ @tagName(scope) ++ "): ";
363:     const instant_unix = InstantUnix.now();
364: 
365:     const stderr = std.io.getStdErr().writer();
366:     var buffered_writer = std.io.bufferedWriter(stderr);
367:     const writer = buffered_writer.writer();
368: 
369:     nosuspend {
370:         instant_unix.format("", .{}, writer) catch return;
371:         writer.print(" " ++ level_text ++ scope_prefix ++ format ++ "\n", args) catch return;
372:         buffered_writer.flush() catch return;
373:     }
374: }
