433: /// Checks that a type does not have implicit padding.
434: pub fn no_padding(comptime T: type) bool {
435:     comptime switch (@typeInfo(T)) {
436:         .void => return true,
437:         .int => return @bitSizeOf(T) == 8 * @sizeOf(T),
438:         .array => |info| return no_padding(info.child),
439:         .@"struct" => |info| {
440:             switch (info.layout) {
441:                 .auto => return false,
442:                 .@"extern" => {
443:                     for (info.fields) |field| {
444:                         if (!no_padding(field.type)) return false;
445:                     }
446: 
447:                     // Check offsets of u128 and pseudo-u256 fields.
448:                     for (info.fields) |field| {
449:                         if (field.type == u128) {
450:                             const offset = @offsetOf(T, field.name);
451:                             if (offset % @sizeOf(u128) != 0) return false;
452: 
453:                             if (@hasField(T, field.name ++ "_padding")) {
454:                                 if (offset % @sizeOf(u256) != 0) return false;
455:                                 if (offset + @sizeOf(u128) !=
456:                                     @offsetOf(T, field.name ++ "_padding"))
457:                                 {
458:                                     return false;
459:                                 }
460:                             }
461:                         }
462:                     }
463: 
464:                     var offset = 0;
465:                     for (info.fields) |field| {
466:                         const field_offset = @offsetOf(T, field.name);
467:                         if (offset != field_offset) return false;
468:                         offset += @sizeOf(field.type);
469:                     }
470:                     return offset == @sizeOf(T);
471:                 },
472:                 .@"packed" => return @bitSizeOf(T) == 8 * @sizeOf(T),
473:             }
474:         },
475:         .@"enum" => |info| {
476:             maybe(info.is_exhaustive);
477:             return no_padding(info.tag_type);
478:         },
479:         .pointer => return false,
480:         .@"union" => return false,
481:         else => return false,
482:     };
483: }
