585: /// Returns a copy of `base` with fields changed according to `diff`.
586: ///
587: /// Intended exclusively for table-driven prototype-based tests. Write
588: /// updates explicitly in production code.
589: pub fn update(base: anytype, diff: anytype) @TypeOf(base) {
590:     assert(builtin.is_test);
591:     assert(@typeInfo(@TypeOf(base)) == .@"struct");
592: 
593:     var updated = base;
594:     inline for (std.meta.fields(@TypeOf(diff))) |f| {
595:         @field(updated, f.name) = @field(diff, f.name);
596:     }
597:     return updated;
598: }
