694: /// True if every value of the type `T` has a unique bit pattern representing it.
695: /// In other words, `T` has no unused bits and no padding.
696: pub fn has_unique_representation(comptime T: type) bool {
697:     switch (@typeInfo(T)) {
698:         else => return false, // TODO can we know if it's true for some of these types ?
699: 
700:         .@"enum",
701:         .error_set,
702:         .@"fn",
703:         => return true,
704: 
705:         .bool => return false,
706: 
707:         .int => |info| return @sizeOf(T) * 8 == info.bits,
708: 
709:         .pointer => |info| return info.size != .slice,
710: 
711:         .array => |info| return comptime has_unique_representation(info.child),
712: 
713:         .@"struct" => |info| {
714:             // Only consider packed structs unique if they are byte aligned.
715:             if (info.backing_integer) |backing_integer| {
716:                 return @sizeOf(T) * 8 == @bitSizeOf(backing_integer);
717:             }
718: 
719:             var sum_size = @as(usize, 0);
720: 
721:             inline for (info.fields) |field| {
722:                 const FieldType = field.type;
723:                 if (comptime !has_unique_representation(FieldType)) return false;
724:                 sum_size += @sizeOf(FieldType);
725:             }
726: 
727:             return @sizeOf(T) == sum_size;
728:         },
729: 
730:         .vector => |info| return comptime has_unique_representation(info.child) and
731:             @sizeOf(T) == @sizeOf(info.child) * info.len,
732:     }
733: }
