842: /// Construct a `union(Enum)` type, where each union "value" type is defined in terms of the
843: /// variant.
844: ///
845: /// That is, `EnumUnionType(Enum, TypeForVariant)` is equivalent to:
846: ///
847: ///   union(Enum) {
848: ///     // For every `e` in `Enum`:
849: ///     e: TypeForVariant(e),
850: ///   }
851: ///
852: pub fn EnumUnionType(
853:     comptime Enum: type,
854:     comptime TypeForVariant: fn (comptime variant: Enum) type,
855: ) type {
856:     const UnionField = std.builtin.Type.UnionField;
857: 
858:     var fields: [std.enums.values(Enum).len]UnionField = undefined;
859:     for (std.enums.values(Enum), 0..) |enum_variant, i| {
860:         fields[i] = .{
861:             .name = @tagName(enum_variant),
862:             .type = TypeForVariant(enum_variant),
863:             .alignment = @alignOf(TypeForVariant(enum_variant)),
864:         };
865:     }
866: 
867:     return @Type(.{ .@"union" = .{
868:         .layout = .auto,
869:         .fields = &fields,
870:         .decls = &.{},
871:         .tag_type = Enum,
872:     } });
873: }
