1102: // Fast alternative to modulo reduction (Note, it is not the same as modulo).
1103: // See https://github.com/lemire/fastrange/ and
1104: // https://lemire.me/blog/2016/06/27/a-fast-alternative-to-the-modulo-reduction/
1105: pub inline fn fastrange(word: u64, p: u64) u64 {
1106:     const lword: u128 = @intCast(word);
1107:     const lp: u128 = @intCast(p);
1108:     const ln: u128 = lword *% lp;
1109:     return @truncate(ln >> 64);
1110: }
