6: /// Parse a "table" of data with the specified schema.
7: /// See test cases for example usage.
8: pub fn parse(comptime Row: type, table_string: []const u8) stdx.BoundedArrayType(Row, 128) {
9:     var rows = stdx.BoundedArrayType(Row, 128){};
10:     var row_strings = std.mem.tokenizeScalar(u8, table_string, '\n');
11:     while (row_strings.next()) |row_string| {
12:         // Ignore blank line.
13:         if (row_string.len == 0) continue;
14: 
15:         var columns = std.mem.tokenizeScalar(u8, row_string, ' ');
16:         const row = parse_data(Row, &columns);
17:         rows.push(row);
18: 
19:         // Ignore trailing line comment.
20:         if (columns.next()) |last| assert(std.mem.eql(u8, last, "//"));
21:     }
22:     return rows;
23: }
