25: fn parse_data(comptime Data: type, tokens: *std.mem.TokenIterator(u8, .scalar)) Data {
26:     return switch (@typeInfo(Data)) {
27:         .optional => |info| parse_data(info.child, tokens),
28:         .@"enum" => field(Data, tokens.next().?),
29:         .void => assert(tokens.next() == null),
30:         .bool => {
31:             const token = tokens.next().?;
32:             inline for (.{ "0", "false", "F" }) |t| {
33:                 if (std.mem.eql(u8, token, t)) return false;
34:             }
35:             inline for (.{ "1", "true", "T" }) |t| {
36:                 if (std.mem.eql(u8, token, t)) return true;
37:             }
38:             std.debug.panic("Unknown boolean: {s}", .{token});
39:         },
40:         .int => |info| {
41:             const max = std.math.maxInt(Data);
42:             const token = tokens.next().?;
43:             // If the first character is a letter ("a-zA-Z"), ignore it. (For example, "A1" → 1).
44:             // This serves as a comment, to help visually disambiguate sequential integer columns.
45:             const offset: usize = if (std.ascii.isAlphabetic(token[0])) 1 else 0;
46:             // Negative unsigned values are computed relative to the maxInt.
47:             if (info.signedness == .unsigned and token[offset] == '-') {
48:                 return max - (std.fmt.parseInt(Data, token[offset + 1 ..], 10) catch unreachable);
49:             }
50:             return std.fmt.parseInt(Data, token[offset..], 10) catch unreachable;
51:         },
52:         .@"struct" => {
53:             var data: Data = undefined;
54:             inline for (std.meta.fields(Data)) |value_field| {
55:                 const Field = value_field.type;
56:                 const value: Field = value: {
57:                     if (comptime value_field.default_value_ptr) |ptr| {
58:                         if (eat(tokens, "_")) {
59:                             const value_ptr: *const Field = @ptrCast(@alignCast(ptr));
60:                             break :value value_ptr.*;
61:                         }
62:                     }
63: 
64:                     break :value parse_data(Field, tokens);
65:                 };
66: 
67:                 @field(data, value_field.name) = value;
68:             }
69:             return data;
70:         },
71:         .array => |info| {
72:             var values: Data = undefined;
73:             for (values[0..]) |*value| {
74:                 value.* = parse_data(info.child, tokens);
75:             }
76:             return values;
77:         },
78:         .@"union" => |info| {
79:             const variant_string = tokens.next().?;
80:             inline for (info.fields) |variant_field| {
81:                 if (std.mem.eql(u8, variant_field.name, variant_string)) {
82:                     return @unionInit(
83:                         Data,
84:                         variant_field.name,
85:                         parse_data(variant_field.type, tokens),
86:                     );
87:                 }
88:             }
89:             std.debug.panic("Unknown union variant: {s}", .{variant_string});
90:         },
91:         else => @compileError("Unimplemented column type: " ++ @typeName(Data)),
92:     };
93: }
