95: fn eat(tokens: *std.mem.TokenIterator(u8, .scalar), token: []const u8) bool {
96:     const index_before = tokens.index;
97:     if (std.mem.eql(u8, tokens.next().?, token)) return true;
98:     tokens.index = index_before;
99:     return false;
100: }
