105: fn field(comptime Enum: type, name: []const u8) Enum {
106:     inline for (std.meta.fields(Enum)) |variant| {
107:         if (std.mem.eql(u8, variant.name, name)) {
108:             return @field(Enum, variant.name);
109:         }
110:     }
111:     std.debug.panic("Unknown field name={s} for type={}", .{ name, Enum });
112: }
