157: const StreamReader = struct {
158:     const LogStderr = std.atomic.Value(enum(u8) { no, yes, on_early_exit });
159: 
160:     log_stderr: LogStderr = LogStderr.init(.on_early_exit),
161:     thread: std.Thread,
162:     file: std.fs.File,
163: 
164:     pub fn start(gpa: std.mem.Allocator, file: std.fs.File) !*StreamReader {
165:         var result = try gpa.create(StreamReader);
166:         errdefer gpa.destroy(result);
167: 
168:         result.* = .{
169:             .thread = undefined,
170:             .file = file,
171:         };
172: 
173:         result.thread = try std.Thread.spawn(.{}, thread_main, .{result});
174:         return result;
175:     }
176: 
177:     pub fn stop(self: *StreamReader, gpa: std.mem.Allocator, process: *std.process.Child) void {
178:         // Shutdown sequence is tricky:
179:         // 1. Terminate the process, but _don't_ close our side of the pipe.
180:         // 2. Wait until the thread exits.
181:         // 3. Close stderr file descriptor.
182:         // TODO(Zig) https://github.com/ziglang/zig/issues/16820
183:         if (builtin.os.tag == .windows) {
184:             const exit_code = 1;
185:             std.os.windows.TerminateProcess(process.id, exit_code) catch {};
186:         } else {
187:             std.posix.kill(process.id, std.posix.SIG.TERM) catch {};
188:         }
189:         assert(process.stderr != null);
190:         self.thread.join();
191:         _ = process.wait() catch unreachable;
192:         assert(process.stderr == null);
193:         gpa.destroy(self);
194:     }
195: 
196:     fn thread_main(reader: *StreamReader) void {
197:         // NB: Zig allocators are not thread safe, so use mmap directly to hold process' stderr.
198:         const allocator = std.heap.page_allocator;
199: 
200:         var buffer = std.ArrayList(u8).init(allocator);
201:         defer buffer.deinit();
202: 
203:         // NB: don't use `readAllAlloc` to get partial output in case of errors.
204:         reader.file.reader().readAllArrayList(&buffer, 100 * MiB) catch {};
205:         switch (reader.log_stderr.load(.seq_cst)) {
206:             .on_early_exit, .yes => {
207:                 log.err("tigerbeetle stderr:\n++++\n{s}\n++++", .{buffer.items});
208:             },
209:             .no => {},
210:         }
211:     }
212: };
