3: //!
4: //! In production code, you can mark certain log lines as "this should be covered by a test".
5: //! In test code, you can then assert that a _specific_ test covers a specific log line. The two
6: //! benefits are:
7: //! - tests are more resilient to refactors
8: //! - production code is more readable (you can immediately jump to a specific test)
9: //!
10: //! At the surface level, this resembles usual code coverage, but the idea is closer to traceability
11: //! from safety-critical systems:
12: //!     <https://en.wikipedia.org/wiki/Requirements_traceability>
13: //!
14: //! That is, the important part is not that a log line is covered at all, but that we can trace
15: //! production code to a single minimal hand-written test which explains why the code needs to
16: //! exist.
17: test "tutorial" {
18:     // Import by a qualified name.
19:     const marks = @import("./marks.zig");
20: 
21:     const production_code = struct {
22:         // In production code, wrap the logger.
23:         const log = marks.wrap_log(std.log.scoped(.my_module));
24: 
25:         fn function_under_test(x: u32) void {
26:             if (x % 2 == 0) {
27:                 // Both `log.info` and log.covered.info` are available.
28:                 // Only second version records coverage.
29:                 log.mark.info("x is even (x={})", .{x});
30:             }
31:         }
32:     };
33: 
34:     // Create a mark with the `mark` function...
35:     const mark = marks.check("x is even");
36:     production_code.function_under_test(92);
37:     try mark.expect_hit(); // ... and don't forget to assert at the end!
38: }
