44: const GlobalStateType = if (builtin.is_test) struct {
45:     mark_name: ?[]const u8 = null,
46:     mark_hit_count: u32 = 0,
47: } else void;
48: 
49: /// Stores the currently active mark and its hit count. State is not synchronized and assumes
50: /// single threaded execution.
51: var global_state: GlobalStateType = .{};
52: 
53: pub const Mark = struct {
54:     name: []const u8,
55: 
56:     pub fn expect_hit(mark: Mark) !void {
57:         comptime assert(builtin.is_test);
58:         assert(global_state.mark_name.?.ptr == mark.name.ptr);
59:         defer global_state = .{};
60: 
61:         if (global_state.mark_hit_count == 0) {
62:             std.debug.print("mark '{s}' not hit", .{mark.name});
63:             return error.MarkNotHit;
64:         }
65:     }
66: 
67:     pub fn expect_not_hit(mark: Mark) !void {
68:         comptime assert(builtin.is_test);
69:         assert(global_state.mark_name.?.ptr == mark.name.ptr);
70:         defer global_state = .{};
71: 
72:         if (global_state.mark_hit_count != 0) {
73:             std.debug.print("mark '{s}' hit", .{mark.name});
74:             return error.MarkHit;
75:         }
76:     }
77: };
78: 
79: pub fn check(name: []const u8) Mark {
80:     comptime assert(builtin.is_test);
81:     assert(global_state.mark_name == null);
82:     assert(global_state.mark_hit_count == 0);
83: 
84:     global_state.mark_name = name;
85:     return Mark{ .name = name };
86: }
