88: pub fn wrap_log(comptime base: type) type {
89:     return struct {
90:         pub const mark = if (builtin.is_test) struct {
91:             pub fn err(comptime fmt: []const u8, args: anytype) void {
92:                 record(fmt);
93:                 base.err(fmt, args);
94:             }
95: 
96:             pub fn warn(comptime fmt: []const u8, args: anytype) void {
97:                 record(fmt);
98:                 base.warn(fmt, args);
99:             }
100: 
101:             pub fn info(comptime fmt: []const u8, args: anytype) void {
102:                 record(fmt);
103:                 base.info(fmt, args);
104:             }
105: 
106:             pub fn debug(comptime fmt: []const u8, args: anytype) void {
107:                 record(fmt);
108:                 base.debug(fmt, args);
109:             }
110:         } else base;
111: 
112:         pub const err = base.err;
113:         pub const warn = base.warn;
114:         pub const info = base.info;
115:         pub const debug = base.debug;
116:     };
117: }
118: 
119: fn record(fmt: []const u8) void {
120:     comptime assert(builtin.is_test);
121:     if (global_state.mark_name) |mark_active| {
122:         if (std.mem.indexOf(u8, fmt, mark_active) != null) {
123:             global_state.mark_hit_count += 1;
124:         }
125:     }
126: }
