617: fn parse_flag_value_check_diagnostic(string: []const u8, diagnostic: ?[]const u8) !void {
618:     const message = diagnostic orelse {
619:         std.debug.print("expected a diagnostic: string='{s}'", .{string});
620:         return error.TestUnexpectedResult;
621:     };
622:     if (!(message.len > 0 and
623:         std.ascii.isLower(message[0]) and
624:         message[message.len - 1] == ':'))
625:     {
626:         std.debug.print("wrong diagnostic format: string='{s}' diagnostic='{s}'", .{
627:             string,
628:             message,
629:         });
630:         return error.TestUnexpectedResult;
631:     }
632: }
