634: fn unique(sorted: []u8) []u8 {
635:     assert(sorted.len > 0);
636: 
637:     var count: usize = 1;
638:     for (1..sorted.len) |index| {
639:         assert(sorted[count - 1] <= sorted[index]);
640:         if (sorted[count - 1] == sorted[index]) {
641:             // Duplicate! Skip to the next index.
642:         } else {
643:             sorted[count] = sorted[index];
644:             count += 1;
645:         }
646:     }
647: 
648:     return sorted[0..count];
649: }
