675:                 p4: ?u32 = null,
676:             },
677:             extended: struct {
678:                 flag: bool = false,
679:                 @"--": void,
680:                 rest: []const []const u8,
681:             },
682:             required: struct {
683:                 foo: u8,
684:                 bar: u8,
685:             },
686:             values: struct {
687:                 int: u32 = 0,
688:                 size: stdx.ByteSize = .{ .value = 0 },
689:                 boolean: bool = false,
