691:                 optional: ?[]const u8 = null,
692:                 choice: enum { marlowe, shakespeare } = .marlowe,
693:             },
694:             subcommand: union(enum) {
695:                 pub const help =
696:                     \\subcommand help
697:                     \\
698:                 ;
699: 
700:                 c1: struct { a: bool = false },
701:                 c2: struct { b: bool = false },
702:             },
703: 
704:             pub const help =
705:                 \\ flags-test-program [flags]
706:                 \\
707:             ;
708:         };
