731:                     try out_stream.print("p2: {s}\n", .{values.p2});
732:                     try out_stream.print("p3: {?}\n", .{values.p3});
733:                     try out_stream.print("p4: {?}\n", .{values.p4});
734:                     try out_stream.print("flag: {}\n", .{values.flag});
735:                 },
736:                 .extended => |values| {
