746:                     try out_stream.print("size: {}\n", .{values.size.bytes()});
747:                     try out_stream.print("boolean: {}\n", .{values.boolean});
748:                     try out_stream.print("path: {s}\n", .{values.path});
749:                     try out_stream.print("optional: {?s}\n", .{values.optional});
