1: //! A tiny pattern/library for testing with expectations ([1], [2]).
2: //!
3: //! On a high level, this is a replacement for `std.testing.expectEqual` which:
4: //!
5: //!   - is less cumbersome to use for complex types,
6: //!   - gives somewhat more useful feedback on a test failure without much investment,
7: //!   - drastically reduces the time to update the tests after refactors,
8: //!   - encourages creation of reusable visualizations for data structures.
9: //!
10: //! Implementation-wise, `snaptest` provides a `Snap` type, which can be thought of as a Zig string
11: //! literal which also remembers its location in the source file, can be diffed with other strings,
12: //! and, crucially, can _update its own source code_ to match the expected value.
13: //!
14: //! Example usage:
15: //!
16: //! ```
17: //! const Snap = @import("snaptest.zig").Snap;
18: //! const snap = Snap.snap;
19: //!
20: //! fn check_addition(x: u32, y: u32, want: Snap) !void {
21: //!     const got = x + y;
22: //!     try want.diff_fmt("{}", .{got});
23: //! }
24: //!
25: //! test "addition" {
26: //!     try check_addition(2, 2, snap(@src(),
27: //!         \\8
28: //!     ));
29: //! }
30: //! ```
31: //!
32: //! Running this test fails, printing the diff between actual result (`4`) and what's specified in
33: //! the source code.
34: //!
35: //! Re-running the test with `SNAP_UPDATE=1` environmental variable auto-magically updates the
36: //! source code to say `\\4`. Alternatively, you can use `snap(...).update()` to auto-update just a
37: //! single test.
38: //!
39: //! Note the `@src()` argument passed to the `snap(...)` invocation --- that's how it knows which
40: //! lines to update.
41: //!
42: //! Snapshots can use `<snap:ignore>` marker to ignore part of input:
43: //!
44: //! ```
45: //! test "time" {
46: //!     var buf: [32]u8 = undefined;
47: //!     const time = try std.fmt.bufPrint(&buf, "it's {}ms", .{
48: //!         std.time.milliTimestamp(),
49: //!     });
50: //!     try Snap.snap(@src(),
51: //!         \\it's <snap:ignore>ms
52: //!     ).diff(time);
53: //! }
54: //! ```
55: //!
56: //! TODO:
57: //!   - This doesn't actually `diff` things yet :o) But running with `SNAP_UPDATE=1` and then using
58: //!     `git diff` is a workable substitute.
59: //!   - Only one test can be updated at a time. To update several, we need to return
60: //!     `error.SkipZigTest` on mismatch and adjust offsets appropriately.
61: //!
62: //! [1]: https://blog.janestreet.com/using-ascii-waveforms-to-test-hardware-designs/
63: //! [2]: https://ianthehenry.com/posts/my-kind-of-repl/
64: const std = @import("std");
65: const assert = std.debug.assert;
66: const builtin = @import("builtin");
67: const SourceLocation = std.builtin.SourceLocation;
68: 
69: const stdx = @import("../stdx.zig");
70: 
71: const MiB = stdx.MiB;
72: 
73: pub const Snap = struct {
74:     comptime {
75:         assert(builtin.is_test);
76:     }
77: 
78:     // Set to `true` to update all snapshots.
79:     pub var update_all: bool = false;
80: 
81:     module_path: []const u8,
82:     location: SourceLocation,
83:     text: []const u8,
84:     update_this: bool = false,
85: 
86:     const SnapFn = fn (location: SourceLocation, text: []const u8) Snap;
87: 
88:     /// Takes the path to the root source file of the current module and creates a snap function.
89:     ///
90:     /// ```
91:     /// const snap = Snap.snap_fn("src");
92:     /// const snap = Snap.snap_fn("src/stdx");
93:     /// ```
94:     ///
95:     /// For the update logic to work, usage *must* be formatted as:
96:     ///
97:     /// ```
98:     /// snap(@src(),
99:     ///     \\Text of the snapshot.
100:     /// )
101:     /// ```
102:     pub fn snap_fn(comptime module_path: []const u8) SnapFn {
103:         return struct {
104:             fn snap(location: SourceLocation, text: []const u8) Snap {
105:                 return init(module_path, location, text);
106:             }
107:         }.snap;
108:     }
109: 
110:     /// Creates a new Snap.
111:     fn init(module_path: []const u8, location: SourceLocation, text: []const u8) Snap {
112:         return Snap{ .module_path = module_path, .location = location, .text = text };
113:     }
114: 
115:     /// Builder-lite method to update just this particular snapshot.
116:     pub fn update(snapshot: *const Snap) Snap {
117:         return Snap{
118:             .module_path = snapshot.module_path,
119:             .location = snapshot.location,
120:             .text = snapshot.text,
121:             .update_this = true,
122:         };
123:     }
124: 
125:     /// To update a snapshot, use whichever you prefer:
126:     ///   - `.update()` method on a particular snap,
127:     ///   - `update_all` const in this file,
128:     ///   - `SNAP_UPDATE` env var.
129:     fn should_update(snapshot: *const Snap) bool {
130:         return snapshot.update_this or update_all or
131:             std.process.hasEnvVarConstant("SNAP_UPDATE");
132:     }
133: 
134:     // Compare the snapshot with a formatted string.
135:     pub fn diff_fmt(snapshot: *const Snap, comptime fmt: []const u8, fmt_args: anytype) !void {
136:         const got = try std.fmt.allocPrint(std.testing.allocator, fmt, fmt_args);
137:         defer std.testing.allocator.free(got);
138: 
139:         try snapshot.diff(got);
140:     }
141: 
142:     // Compare the snapshot with the zon json serialization of a `value`.
143:     pub fn diff_zon(
144:         snapshot: *const Snap,
145:         value: anytype,
146:     ) !void {
147:         var got: std.ArrayListUnmanaged(u8) = .empty;
148:         defer got.deinit(std.testing.allocator);
149: 
150:         try std.zon.stringify.serialize(value, .{}, got.writer(std.testing.allocator));
151:         try snapshot.diff(got.items);
152:     }
153: 
154:     pub fn diff_hex(snapshot: *const Snap, value: []const u8) !void {
155:         var buffer: std.ArrayListUnmanaged(u8) = .empty;
156:         defer buffer.deinit(std.testing.allocator);
157: 
158:         try hexdump(value, buffer.writer(std.testing.allocator).any());
159:         try snapshot.diff(buffer.items);
160:     }
161: 
162:     // Compare the snapshot with a given string.
163:     pub fn diff(snapshot: *const Snap, got: []const u8) !void {
164:         if (equal_excluding_ignored(got, snapshot.text)) return;
165: 
166:         std.debug.print(
167:             \\Snapshot differs.
168:             \\Want:
169:             \\----
170:             \\{s}
171:             \\----
172:             \\Got:
173:             \\----
174:             \\{s}
175:             \\----
176:             \\
177:         ,
178:             .{
179:                 snapshot.text,
180:                 got,
181:             },
182:         );
183: 
184:         if (!snapshot.should_update()) {
185:             std.debug.print(
186:                 "Rerun with SNAP_UPDATE=1 environmental variable to update the snapshot.\n",
187:                 .{},
188:             );
189:             return error.SnapDiff;
190:         }
191: 
192:         var arena_instance = std.heap.ArenaAllocator.init(std.testing.allocator);
193:         defer arena_instance.deinit();
194: 
195:         const arena = arena_instance.allocator();
196:         const file_path_relative = try std.fs.path.join(
197:             arena,
198:             // The file location is relative to the module root path.
199:             &.{ snapshot.module_path, snapshot.location.file },
200:         );
201: 
202:         const file_text = try std.fs.cwd().readFileAlloc(arena, file_path_relative, 1 * MiB);
203:         var file_text_updated = try std.ArrayList(u8).initCapacity(arena, file_text.len);
204: 
205:         const line_zero_based = snapshot.location.line - 1;
206:         const range = snap_range(file_text, line_zero_based);
207: 
208:         const snapshot_prefix = file_text[0..range.start];
209:         const snapshot_text = file_text[range.start..range.end];
210:         const snapshot_suffix = file_text[range.end..];
211: 
212:         const indent = get_indent(snapshot_text);
213: 
214:         try file_text_updated.appendSlice(snapshot_prefix);
215:         {
216:             var lines = std.mem.splitScalar(u8, got, '\n');
217:             while (lines.next()) |line| {
218:                 try file_text_updated.writer().print("{s}\\\\{s}\n", .{ indent, line });
219:             }
220:         }
221:         try file_text_updated.appendSlice(snapshot_suffix);
222: 
223:         try std.fs.cwd().writeFile(.{
224:             .sub_path = file_path_relative,
225:             .data = file_text_updated.items,
226:         });
227: 
228:         std.debug.print("Updated {s}\n", .{file_path_relative});
229:         return error.SnapUpdated;
230:     }
231: };
