233: fn equal_excluding_ignored(got: []const u8, snapshot: []const u8) bool {
234:     // Don't allow ignoring suffixes and prefixes, as that makes it easy to miss trailing or leading
235:     // data.
236:     assert(!std.mem.startsWith(u8, snapshot, "<snap:ignore>"));
237:     assert(!std.mem.endsWith(u8, snapshot, "<snap:ignore>"));
238: 
239:     var got_rest = got;
240:     var snapshot_rest = snapshot;
241:     for (0..10) |_| {
242:         // Cut the part before the first ignore, it should be equal between two strings...
243:         const common_prefix, snapshot_rest = stdx.cut(snapshot_rest, "<snap:ignore>") orelse break;
244:         got_rest = stdx.cut_prefix(got_rest, common_prefix) orelse return false;
245: 
246:         // ...then find the next part that should match, and cut up to that.
247:         const common_middle, _ =
248:             stdx.cut(snapshot_rest, "<snap:ignore>") orelse .{ snapshot_rest, "" };
249:         assert(common_middle.len > 0);
250:         snapshot_rest = stdx.cut_prefix(snapshot_rest, common_middle).?;
251: 
252:         const ignored, got_rest = stdx.cut(got_rest, common_middle) orelse return false;
253:         // If <snap:ignore> matched an empty string, or several lines, report it as an error.
254:         if (ignored.len == 0) return false;
255:         if (std.mem.indexOfScalar(u8, ignored, '\n') != null) return false;
256:     } else @panic("more than 10 ignores");
257: 
258:     return std.mem.eql(u8, got_rest, snapshot_rest);
259: }
