263:     try equal_excluding_ignored_case("ABBA", "A<snap:ignore>A", true);
264:     try equal_excluding_ignored_case("ABBACABA", "AB<snap:ignore>CA<snap:ignore>A", true);
265: 
266:     try equal_excluding_ignored_case("ABA", "ACA", false);
267:     try equal_excluding_ignored_case("ABBA", "A<snap:ignore>C", false);
268:     try equal_excluding_ignored_case("ABBACABA", "AB<snap:ignore>DA<snap:ignore>BA", false);
269:     try equal_excluding_ignored_case("ABBACABA", "AB<snap:ignore>BA<snap:ignore>DA", false);
270:     try equal_excluding_ignored_case("ABA", "AB<snap:ignore>A", false);
271:     try equal_excluding_ignored_case("A\nB\nA", "A<snap:ignore>A", false);
272: }
273: 
274: fn equal_excluding_ignored_case(got: []const u8, snapshot: []const u8, ok: bool) !void {
275:     try std.testing.expectEqual(equal_excluding_ignored(got, snapshot), ok);
276: }
