278: const Range = struct { start: usize, end: usize };
279: 
280: /// Extracts the range of the snapshot. Assumes that the snapshot is formatted as
281: ///
282: /// ```
283: /// snap(@src(),
284: ///     \\first line
285: ///     \\second line
286: /// )
287: /// ```
288: ///
289: /// We could make this more robust by using `std.zig.Ast`, but sticking to manual string processing
290: /// is simpler, and enforced consistent style of snapshots is a good thing.
291: ///
292: /// While we expect to find a snapshot after a given line, this is not guaranteed (the file could
293: /// have been modified between compilation and running the test), but should be rare enough to
294: /// just fail with an assertion.
295: fn snap_range(text: []const u8, src_line: u32) Range {
296:     var offset: usize = 0;
297:     var line_number: u32 = 0;
298: 
299:     var lines = std.mem.splitScalar(u8, text, '\n');
300:     const snap_start = while (lines.next()) |line| : (line_number += 1) {
301:         if (line_number == src_line) {
302:             assert(std.mem.indexOf(u8, line, "@src()") != null);
303:         }
304:         if (line_number == src_line + 1) {
305:             assert(is_multiline_string(line));
306:             break offset;
307:         }
308:         offset += line.len + 1; // 1 for \n
309:     } else unreachable;
310: 
311:     lines = std.mem.splitScalar(u8, text[snap_start..], '\n');
312:     const snap_end = while (lines.next()) |line| {
313:         if (!is_multiline_string(line)) {
314:             break offset;
315:         }
316:         offset += line.len + 1; // 1 for \n
317:     } else unreachable;
318: 
319:     return Range{ .start = snap_start, .end = snap_end };
320: }
321: 
322: fn is_multiline_string(line: []const u8) bool {
323:     for (line, 0..) |c, i| {
324:         switch (c) {
325:             ' ' => {},
326:             '\\' => return (i + 1 < line.len and line[i + 1] == '\\'),
327:             else => return false,
328:         }
329:     }
330:     return false;
331: }
332: 
333: fn get_indent(line: []const u8) []const u8 {
334:     for (line, 0..) |c, i| {
335:         if (c != ' ') return line[0..i];
336:     }
337:     return line;
338: }
339: 
340: fn hexdump(bytes: []const u8, writer: std.io.AnyWriter) !void {
341:     for (bytes, 0..) |byte, index| {
342:         if (index > 0) {
343:             const space = if (index % 16 == 0) "\n" else if (index % 8 == 0) "  " else " ";
344:             try writer.writeAll(space);
345:         }
346:         try writer.print("{x:02}", .{byte});
347:     }
348: }
