190: const SourceFile = struct {
191:     path: []const u8,
192:     text: [:0]const u8,
193: 
194:     // NB: The return value borrows both path and buffer.
195:     fn read(path: []const u8, buffer: []u8) !SourceFile {
196:         const bytes_read = (try std.fs.cwd().readFile(path, buffer)).len;
197:         if (bytes_read >= buffer.len - 1) return error.FileTooLong;
198:         buffer[bytes_read] = 0;
199:         return .{
200:             .path = path,
201:             .text = buffer[0..bytes_read :0],
202:         };
203:     }
204: 
205:     fn has_extension(file: SourceFile, extension: []const u8) bool {
206:         assert(extension.len > 0);
207:         assert(extension[0] == '.');
208:         return std.mem.endsWith(u8, file.path, extension);
209:     }
210: 
211:     // O(N), but only invoked on the cold path (when there are errors).
212:     fn line_number(file: SourceFile, offset: usize) usize {
213:         assert(offset <= file.text.len);
214:         // +1: Line _index_ is zero-based, line _number_ is one-based.
215:         return std.mem.count(u8, file.text[0..offset], "\n") + 1;
216:     }
217: };
