242: fn check_tidy_file(file_path: []const u8, file_text: [:0]const u8, want: Snap) !void {
243:     const gpa = std.testing.allocator;
244: 
245:     var counter: IdentifierCounter = try .init(gpa);
246:     defer counter.deinit(gpa);
247: 
248:     var errors: Errors = .{ .captured = .{} };
249:     defer errors.captured.?.deinit(std.testing.allocator);
250: 
251:     try tidy_file(gpa, &counter, .{ .path = file_path, .text = file_text }, &errors);
252:     const got = errors.captured.?.items;
253: 
