258: fn tidy_control_characters(file: SourceFile, errors: *Errors) void {
259:     const binary_file_extensions: []const []const u8 = &.{ ".ico", ".png", ".webp" };
260:     for (binary_file_extensions) |extension| {
261:         if (file.has_extension(extension)) return;
262:     }
263: 
264:     const allowed = .{
265:         .@"\r" = file.has_extension(".bat"),
266: 
267:         // Visual Studio insists on \t, taking the best from `make`.
268:         // Go uses tabs.
269:         .@"\t" = file.has_extension(".sln") or
270:             (file.has_extension(".go") or
271:                 (file.has_extension(".md") and mem.indexOf(u8, file.text, "```go") != null)),
272:     };
273: 
274:     var remaining = file.text;
275:     while (mem.indexOfAny(u8, remaining, "\r\t")) |index| {
276:         const offset = index + (file.text.len - remaining.len);
277:         inline for (comptime std.meta.fieldNames(@TypeOf(allowed))) |field| {
278:             if (remaining[index] == field[0]) {
279:                 if (!@field(allowed, field)) {
