468: /// All functions using the `CamelCase` naming convention return a type,
469: /// so we enforce that the function name also ends with the `Type` suffix.
470: fn tidy_type_functions(file: SourceFile, errors: *Errors) void {
471:     var line_index: u32 = 0;
472:     var it = std.mem.splitScalar(u8, file.text, '\n');
473:     while (it.next()) |line| : (line_index += 1) {
474:         // Zig fmt enforces that the pattern `fn Foo(` is not split across multiple lines.
475: 
476:         const prefix, const suffix = stdx.cut(line, "fn ") orelse continue;
477:         // Not all `fn ` tokens are functions, some may be `callback_fn` for example.
478:         // Functions appear at the beginning of a line or after a whitespace.
479:         if (prefix.len > 0 and prefix[prefix.len - 1] != ' ') continue;
480:         const function_name, _ = stdx.cut(suffix, "(") orelse continue;
481:         if (function_name.len == 0) continue; // E.g: `*const fn (*anyopaque) void`.
482:         assert(function_name.len > 0);
483: 
484:         // Skipping naming convention that requires upper-case functions.
485:         if (std.mem.startsWith(u8, function_name, "JNI_")) continue;
486:         // Windows use CamelCase functions.
487:         if (std.mem.indexOf(u8, line, "extern \"kernel32\"") != null) continue;
488: 
489:         if (std.ascii.isUpper(function_name[0])) {
490:             if (!std.mem.endsWith(u8, function_name, "Type")) {
491:                 errors.add_bad_type_function_name(file, line_index, function_name);
492:             }
493:         }
494:     }
495: }
